const challenges = [
    { title: 'Route Optimization', description: 'Dynamic route planning to reduce transit time.', img: 'https://via.placeholder.com/300x180?text=Route+Optimization' },
    { title: 'Warehouse Safety', description: 'Track safety incidents and compliance scores.', img: 'https://via.placeholder.com/300x180?text=Warehouse+Safety' },
    { title: 'Fast Delivery', description: 'Improve on-time delivery for Hyderabad routes.', img: 'https://via.placeholder.com/300x180?text=Fast+Delivery' },
    { title: 'Inventory Accuracy', description: 'End-to-end stock reconciliation visibility.', img: 'https://via.placeholder.com/300x180?text=Inventory+Accuracy' },
];

function BusinessChallenges() {
    return (
        <section style={{ marginTop: '18px' }}>
            <h2>Business Challenges</h2>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '12px', marginTop: '12px' }}>
                {challenges.map((item) => (
                    <div
                        key={item.title}
                        style={{
                            position: 'relative',
                            overflow: 'hidden',
                            borderRadius: '12px',
                            cursor: 'pointer',
                            boxShadow: '0 4px 16px rgba(0,0,0,0.08)',
                            transition: 'transform 0.2s ease',
                        }}
                        onMouseEnter={(e) => (e.currentTarget.style.transform = 'scale(1.02)')}
                        onMouseLeave={(e) => (e.currentTarget.style.transform = 'scale(1)')}
                    >
                        <img src={item.img} alt={item.title} style={{ width: '100%', height: 170, objectFit: 'cover' }} />
                        <div style={{ padding: '10px', background: '#fff' }}>
                            <strong>{item.title}</strong>
                            <p style={{ margin: '4px 0 0', fontSize: '0.9rem', color: '#4b5563' }}>{item.description}</p>
                        </div>
                    </div>
                ))}
            </div>
        </section>
    );
}

export default BusinessChallenges;
